package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames_defaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withAllowMissingColumnNames();
        assertNotNull(result);
        assertTrue(result.getAllowMissingColumnNames());
        // The original format should not be modified (immutability)
        assertFalse(format.getAllowMissingColumnNames());
        // The returned instance should be different if original allowMissingColumnNames was false
        if (!format.getAllowMissingColumnNames()) {
            assertNotSame(format, result);
        }
    }

    @Test
    void testWithAllowMissingColumnNames_withFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
        CSVFormat result = format.withAllowMissingColumnNames();
        assertNotNull(result);
        assertTrue(result.getAllowMissingColumnNames());
        assertNotSame(format, result);
    }
}
